from django.contrib.auth import authenticate, login
from django.utils.saml2 import parse_assertion, SAMLException

class SAMLServiceProvider(object):
    def __init__(self):
        self.nameid_format = None
        self.attributes = {}

    def handle_post_response(self, request):
        try:
            assertion = parse_assertion(request.POST['SAMLResponse'])
            nameid = assertion['NameID']
            attributes = assertion['AttributeStatement']['Attributes']

            # Validate the XML structure
            if 'SAML' not in assertion or 'Assertion' not in assertion:
                raise SAMLException('Invalid SAML Response')

            # Extract user information from attributes
            self.attributes = {}
            for attribute in attributes:
                name = attribute['Attribute'][0]['Name']
                values = [value['Value'][0]['Value'] for value in attribute['AttributeValue']]
                self.attributes[name] = values

            # Create Django user session based on NameID and attributes
            user = authenticate(request, nameid=nameid, **self.attributes)
            login(request, user)
        except SAMLException as e:
            print('Error handling SAML POST response:', str(e))